343	// limited version of the schema, focussed on what is needed for the implementation
344	// this approach limits breakages when the API changes and increases efficiency
345	const lumaGenerationResponseSchema = lazySchema(() =>
346	  zodSchema(
347	    z.object({
348	      id: z.string(),
349	      state: z.enum(['queued', 'dreaming', 'completed', 'failed']),
350	      failure_reason: z.string().nullish(),
351	      assets: z
352	        .object({
353	          image: z.string(), // URL of the generated image
354	        })
355	        .nullish(),
356	    }),
357	  ),
358	);
359	
360	const lumaErrorSchema = z.object({
361	  detail: z.array(
362	    z.object({
363	      type: z.string(),
364	      loc: z.array(z.string()),
365	      msg: z.string(),
366	      input: z.string(),
367	      ctx: z
368	        .object({
369	          expected: z.string(),
370	        })
371	        .nullish(),
372	    }),
373	  ),
374	});
375	
376	export type LumaErrorData = z.infer<typeof lumaErrorSchema>;
