import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  FetchFunction,
  combineHeaders,
  createJsonResponseHandler,
  createJsonErrorResponseHandler,
  postJsonToApi,
  InferSchema,
  lazySchema,
  parseProviderOptions,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: string,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
    files,
    mask,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'This model does not support aspect ratio. Use `size` instead.',
      });
    }

    if (seed != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'seed',
        details: 'This model does not support the `seed` option.',
      });
    }

    if (files != null && files.length > 0) {
      warnings.push({
        type: 'unsupported',
        feature: 'files',
        details: 'This model does not support image editing.',
      });
    }

    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'mask',
        details: 'This model does not support image masking.',
      });
    }

    // Parse and validate provider options
    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelartImageModelOptionsSchema,
    });

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
    const fullHeaders = combineHeaders(this.config.headers(), headers);

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generations`,
      headers: fullHeaders,
      body: {
        model: this.modelId,
        prompt,
        n,
        size: pixelartOptions?.size ?? size,
        ...(pixelartOptions?.style
          ? { style: pixelartOptions.style }
          : {}),
        ...(pixelartOptions?.pixelDensity != null
          ? { pixel_density: pixelartOptions.pixelDensity }
          : {}),
        response_format: 'b64_json',
      },
      abortSignal,
      fetch: this.config.fetch,
      failedResponseHandler: createJsonErrorResponseHandler({
        errorSchema: pixelartErrorSchema,
        errorToMessage: (error: PixelArtErrorData) => error.error.message,
      }),
      successfulResponseHandler: createJsonResponseHandler(
        pixelartImageResponseSchema,
      ),
    });

    return {
      images: response.data.map(
        (item: { b64_json: string }) => item.b64_json,
      ),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
    };
  }
}

// limited version of the schema, focused on what is needed for the implementation
// this approach limits breakages when the API changes and increases efficiency
const pixelartImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      data: z.array(
        z.object({
          b64_json: z.string(),
        }),
      ),
    }),
  ),
);

const pixelartErrorSchema = z.object({
  error: z.object({
    message: z.string(),
    type: z.string().nullish(),
    code: z.string().nullish(),
  }),
});

export type PixelArtErrorData = z.infer<typeof pixelartErrorSchema>;

/**
 * Provider options schema for PixelArt image generation.
 */
export const pixelartImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      /**
       * The visual style of the generated pixel art.
       * - `pixel`: Standard pixel art style (default)
       * - `retro`: Retro/vintage console style
       * - `8bit`: Classic 8-bit video game style
       */
      style: z.enum(['pixel', 'retro', '8bit']).nullish(),

      /**
       * The pixel density of the generated image.
       * Higher values produce more detailed pixel art.
       */
      pixelDensity: z.number().nullish(),

      /**
       * Image size string, e.g. "256x256", "512x512".
       */
      size: z.string().nullish(),
    }),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelartImageModelOptionsSchema
>;

